param([switch]$Quick)
$ErrorActionPreference='Stop'
$Root=Resolve-Path (Join-Path $PSScriptRoot '../..')
Import-Module (Join-Path $Root 'eng/BusinessOS.Engineering.psm1') -Force
Import-Module (Join-Path $Root 'eng/BusinessOS.Provisioning.psm1') -Force
$log=Join-Path $Root '.cache/environment-tests.log'; New-Item -ItemType Directory -Force (Split-Path $log)|Out-Null; ''|Set-Content $log
$script:Failures=0
function Assert($Name,[scriptblock]$Body){try{& $Body; "PASS $Name"|Tee-Object $log -Append}catch{$script:Failures++; "FAIL $Name :: $($_.Exception.Message)"|Tee-Object $log -Append; Write-Error $_}}
function Invoke-ProcessForTest([string]$File,[string[]]$Args,[string]$Cwd){$psi=[Diagnostics.ProcessStartInfo]::new();$psi.FileName=$File;$psi.WorkingDirectory=$Cwd;$psi.UseShellExecute=$false;$psi.RedirectStandardOutput=$true;$psi.RedirectStandardError=$true;foreach($a in $Args){[void]$psi.ArgumentList.Add($a)};$p=[Diagnostics.Process]::Start($psi);$outTask=$p.StandardOutput.ReadToEndAsync();$errTask=$p.StandardError.ReadToEndAsync();$p.WaitForExit();[pscustomobject]@{ExitCode=$p.ExitCode;Output=$outTask.GetAwaiter().GetResult();Error=$errTask.GetAwaiter().GetResult();Combined=($outTask.GetAwaiter().GetResult()+"`n"+$errTask.GetAwaiter().GetResult())}}
function Invoke-ExpectSuccess([string]$File,[string[]]$Args,[string]$Cwd){$r=Invoke-ProcessForTest $File $Args $Cwd; if($r.ExitCode -ne 0){throw "Expected success, got $($r.ExitCode): $($r.Combined)"}; $r}
function Invoke-ExpectFailure([string]$File,[string[]]$Args,[string]$Cwd,[string]$Contains){$r=Invoke-ProcessForTest $File $Args $Cwd; if($r.ExitCode -eq 0){throw "Expected failure, got success: $($r.Combined)"}; if($Contains -and $r.Combined -notmatch [regex]::Escape($Contains)){throw "Failure did not contain '$Contains': $($r.Combined)"}; $r}
function Copy-FixtureRepo([string]$BaseName = ("BusinessOS fixture " + [Guid]::NewGuid())){ $d=Join-Path ([IO.Path]::GetTempPath()) $BaseName; foreach($dir in 'eng','tests/environment','src/BusinessOS.Desktop','src/BusinessOS.AppHost','src/BuildingBlocks/BusinessOS.BuildingBlocks.Domain','src/BuildingBlocks/BusinessOS.BuildingBlocks.Application','tests/BusinessOS.UnitTests','tests/BusinessOS.ArchitectureTests'){New-Item -ItemType Directory -Force (Join-Path $d $dir)|Out-Null}; foreach($f in 'environment.lock.json','environment.bootstrap.env','BusinessOS.Engineering.psm1','BusinessOS.Provisioning.psm1','doctor.ps1','setup-environment.ps1','setup-environment.sh','activate-environment.ps1','activate-environment.sh','verify-cross-platform.ps1','verify-windows.ps1','smoke-test-desktop.ps1'){Copy-Item (Join-Path $Root "eng/$f") (Join-Path $d "eng/$f")}; Copy-Item (Join-Path $Root 'tests/environment/Environment.Tests.ps1') (Join-Path $d 'tests/environment/Environment.Tests.ps1'); Copy-Item (Join-Path $Root 'global.json') (Join-Path $d 'global.json'); Copy-Item (Join-Path $Root 'BusinessOS.CrossPlatform.slnf') (Join-Path $d 'BusinessOS.CrossPlatform.slnf'); 'Microsoft Visual Studio Solution File, Format Version 12.00','Project("{x}") = "BusinessOS.Desktop", "src\BusinessOS.Desktop\BusinessOS.Desktop.csproj", "{y}"'|Set-Content (Join-Path $d 'BusinessOS.sln'); foreach($p in 'src/BusinessOS.Desktop/BusinessOS.Desktop.csproj','src/BusinessOS.AppHost/BusinessOS.AppHost.csproj','src/BuildingBlocks/BusinessOS.BuildingBlocks.Domain/BusinessOS.BuildingBlocks.Domain.csproj','src/BuildingBlocks/BusinessOS.BuildingBlocks.Application/BusinessOS.BuildingBlocks.Application.csproj','tests/BusinessOS.UnitTests/BusinessOS.UnitTests.csproj','tests/BusinessOS.ArchitectureTests/BusinessOS.ArchitectureTests.csproj'){'<Project Sdk="Microsoft.NET.Sdk"><PropertyGroup><TargetFramework>net10.0</TargetFramework></PropertyGroup><ItemGroup><PackageReference Include="Microsoft.WindowsAppSDK" Condition="false" /></ItemGroup></Project>'|Set-Content (Join-Path $d $p)}; git -C $d init *> $null; git -C $d add . *> $null; $d }
function New-FileWithHash([string]$Text){$f=Join-Path ([IO.Path]::GetTempPath()) ([Guid]::NewGuid()); $Text|Set-Content -NoNewline $f; $f}
function Read-Resolved($Dir){ Get-Content (Join-Path $Dir '.cache/environment.resolved.json') -Raw | ConvertFrom-Json }
function Compare-Resolved($A,$B){ foreach($p in 'dotnetExecutable','dotnetRoot','dotnetSource','powershellExecutable','powershellRoot','powershellSource','nugetPackages','dotnetCliHome','powershellModuleRoot'){ if($A.$p -ne $B.$p){throw "resolved state changed: $p"} } }
function HostToolsMatch($Lock){ if(-not(Get-Command dotnet -ErrorAction SilentlyContinue) -or -not(Get-Command pwsh -ErrorAction SilentlyContinue)){return $false}; ((& dotnet --version) -eq $Lock.dotnetSdk) -and ((& pwsh -NoProfile -Command '$PSVersionTable.PSVersion.ToString()') -eq $Lock.powershell.version) }
function New-ZipArchive($Path,[string]$EntryName){ Add-Type -AssemblyName System.IO.Compression.FileSystem; $dir=Join-Path ([IO.Path]::GetTempPath()) ([Guid]::NewGuid()); New-Item -ItemType Directory -Force $dir|Out-Null; if($EntryName){'x'|Set-Content -NoNewline (Join-Path $dir $EntryName)}; [IO.Compression.ZipFile]::CreateFromDirectory($dir,$Path) }
function New-TarGzArchive($Path,[string]$EntryName){ $dir=Join-Path ([IO.Path]::GetTempPath()) ([Guid]::NewGuid()); New-Item -ItemType Directory -Force $dir|Out-Null; if($EntryName){'x'|Set-Content -NoNewline (Join-Path $dir $EntryName)}; Invoke-ExpectSuccess tar @('-czf',$Path,'-C',$dir,'.') $Root|Out-Null }
Assert 'manifest, bootstrap, Dockerfile, and global.json are coherent' { $b=Read-BusinessOSBootstrapLock; $m=Read-BusinessOSEnvironmentLock; $g=Get-Content (Join-Path $Root 'global.json') -Raw|ConvertFrom-Json; $docker=Get-Content (Join-Path $Root '.devcontainer/Dockerfile') -Raw; $expectedDotnet=@{'linux-x64'='F78DBAC30C9AF2230D67FF5C224DE3A5DBF63F8A78D1C206594DEDB80E6909D2CC8A9D865D5105C72C2FD2AA266FC0C6C77DEDAC60408CBCCF272B116BD11B07';'osx-x64'='595C3C661A705A256F52E03E3AEEB86753AD6F9AA3D59F487304CDBBB744A39F4E3FA6445A60CDED6BC78E12F51D52ED5A183EA70A0560B96BED61FB83958F81';'win-x64'='24B033418A3969EFFD49B4651EF7EBBFFEB284773B99545D78DCE61A82E57F38DB7FACDB013C609BA15573C072F0E093363AE470824A6847F3C6111078C1FB64'}; if($b.DOTNET_SDK_VERSION -ne $m.dotnetSdk -or $m.dotnetSdk -ne $g.sdk.version){throw 'dotnet version mismatch'}; foreach($rid in 'linux-x64','osx-x64','win-x64'){ $envRid=$rid.ToUpperInvariant().Replace('-','_'); $urlProp="DOTNET_${envRid}_URL"; $shaProp="DOTNET_${envRid}_SHA512"; if($b.$urlProp -ne $m.dotnet.archives.$rid.url){throw "dotnet url mismatch $rid"}; if($b.$shaProp -ne $m.dotnet.archives.$rid.sha512){throw "dotnet sha mismatch $rid"}; if($m.dotnet.archives.$rid.sha512 -ne $expectedDotnet[$rid]){throw "unexpected official dotnet sha $rid"}; if($m.dotnet.archives.$rid.sha512 -match '^(.)\1+$'){throw "placeholder dotnet hash $rid"} }; if($b.POWERSHELL_LINUX_X64_URL -ne $m.powershell.archives.'linux-x64'.urls[0] -or $b.POWERSHELL_LINUX_X64_SHA256 -ne $m.powershell.archives.'linux-x64'.sha256){throw 'PowerShell linux mismatch'}; if($docker -notmatch [regex]::Escape($m.dotnetSdk) -or $docker -notmatch [regex]::Escape($m.powershell.version) -or $docker -notmatch [regex]::Escape($m.powershell.archives.'linux-x64'.sha256)){throw 'Dockerfile mismatch'}; if($b.DOTNET_ROOT_REL -ne $m.dotnetRoot -or $b.POWERSHELL_ROOT_REL -ne $m.powershellRoot -or $b.NUGET_CACHE_REL -ne $m.nugetCache -or $b.DOTNET_HOME_REL -ne $m.dotnetHome){throw 'tool/cache root mismatch'} }
Assert 'doctor accepts a complete valid fixture' { $d=Copy-FixtureRepo; Invoke-ExpectSuccess pwsh @('-NoProfile','-File',(Join-Path $d 'eng/doctor.ps1'),'-Mode','CrossPlatform','-SkipEnvironmentTests') $d | Out-Null }
Assert 'PowerShell activation is idempotent' { $d=Copy-FixtureRepo; New-Item -ItemType Directory -Force (Join-Path $d '.cache')|Out-Null; $resolved=[pscustomobject]@{dotnetExecutable=(Join-Path $d '.tools/dotnet/dotnet');dotnetRoot=(Join-Path $d '.tools/dotnet');dotnetSource='local';powershellExecutable=(Join-Path $d '.tools/powershell/pwsh');powershellRoot=(Join-Path $d '.tools/powershell');powershellSource='local';nugetPackages=(Join-Path $d '.cache/nuget');dotnetCliHome=(Join-Path $d '.cache/dotnet-home');powershellModuleRoot=(Join-Path $d '.tools/powershell-modules')}; $resolved|ConvertTo-Json|Set-Content (Join-Path $d '.cache/environment.resolved.json'); . (Join-Path $d 'eng/activate-environment.ps1'); $p1=$env:PATH; $m1=$env:PSModulePath; . (Join-Path $d 'eng/activate-environment.ps1'); if($env:PATH -ne $p1 -or $env:PSModulePath -ne $m1){throw 'activation duplicated paths'} }
Assert 'PowerShell setup is idempotent with matching host tools' { $lock=Read-BusinessOSEnvironmentLock; if(-not(HostToolsMatch $lock)){Write-Host 'SKIPPED host tools do not match manifest'; return}; $d=Copy-FixtureRepo; Invoke-ExpectSuccess pwsh @('-NoProfile','-File','./eng/setup-environment.ps1') $d|Out-Null; $r1=Read-Resolved $d; Invoke-ExpectSuccess pwsh @('-NoProfile','-File','./eng/setup-environment.ps1') $d|Out-Null; $r2=Read-Resolved $d; Compare-Resolved $r1 $r2 }
Assert 'Bash setup is idempotent with matching host tools and special path' { if($IsWindows -or -not(Get-Command bash -ErrorAction SilentlyContinue)){Write-Host 'SKIPPED bash setup test on this platform'; return}; $lock=Read-BusinessOSEnvironmentLock; if(-not(HostToolsMatch $lock)){Write-Host 'SKIPPED host tools do not match manifest'; return}; $expectedDotnetExecutable=(Get-Command dotnet -ErrorAction Stop).Source; $expectedDotnetRoot=Split-Path -Parent $expectedDotnetExecutable; $expectedPwshExecutable=(Get-Command pwsh -ErrorAction Stop).Source; $expectedPwshRoot=Split-Path -Parent $expectedPwshExecutable; $d=Copy-FixtureRepo "Business OS a'b`$c\d(e) $([Guid]::NewGuid())"; Invoke-ExpectSuccess bash @('-c','./eng/setup-environment.sh') $d|Out-Null; $r1=Read-Resolved $d; $firstEnv=Get-Content (Join-Path $d '.cache/environment.resolved.env') -Raw; $firstJson=Get-Content (Join-Path $d '.cache/environment.resolved.json') -Raw; Invoke-ExpectSuccess bash @('-c','./eng/setup-environment.sh') $d|Out-Null; $r2=Read-Resolved $d; $secondEnv=Get-Content (Join-Path $d '.cache/environment.resolved.env') -Raw; $secondJson=Get-Content (Join-Path $d '.cache/environment.resolved.json') -Raw; if($secondEnv -ne $firstEnv){throw 'Resolved ENV changed after second Bash setup'}; Compare-Resolved $r1 $r2; if($r2.dotnetExecutable -ne $expectedDotnetExecutable){throw 'Bash setup did not resolve expected host dotnet executable'}; if($r2.dotnetRoot -ne $expectedDotnetRoot){throw 'Bash setup did not resolve expected host dotnet root'}; if($r2.powershellExecutable -ne $expectedPwshExecutable){throw 'Bash setup did not resolve expected host PowerShell executable'}; if($r2.powershellRoot -ne $expectedPwshRoot){throw 'Bash setup did not resolve expected host PowerShell root'}; $expectedNuget=Join-Path $d '.cache/nuget'; $expectedDotnetHome=Join-Path $d '.cache/dotnet-home'; $expectedPsModule=Join-Path $d '.tools/powershell-modules'; if($r2.nugetPackages -ne $expectedNuget){throw 'Bash setup did not resolve expected fixture NuGet cache'}; if($r2.dotnetCliHome -ne $expectedDotnetHome){throw 'Bash setup did not resolve expected fixture dotnet-home'}; if($r2.powershellModuleRoot -ne $expectedPsModule){throw 'Bash setup did not resolve expected fixture PSModule path'}; $envResult=Invoke-ExpectSuccess bash @('-c','set -euo pipefail; set -a; source .cache/environment.resolved.env; set +a; pwsh -NoProfile -Command ''[ordered]@{ dotnetExecutable = $env:DOTNET_EXE; dotnetRoot = $env:DOTNET_ROOT; dotnetSource = $env:DOTNET_SOURCE; powershellExecutable = $env:PWSH_EXE; powershellRoot = $env:POWERSHELL_ROOT; powershellSource = $env:POWERSHELL_SOURCE; nugetPackages = $env:NUGET_PACKAGES; dotnetCliHome = $env:DOTNET_CLI_HOME; powershellModuleRoot = $env:PSMODULE_ROOT } | ConvertTo-Json -Compress''') $d; if([string]::IsNullOrWhiteSpace($envResult.Output)){throw 'Bash sourced environment produced empty JSON output'}; $resolvedFromEnv=$envResult.Output | ConvertFrom-Json; Compare-Resolved $resolvedFromEnv $r2 }
Assert 'doctor rejects empty solution with concrete output' { $d=Copy-FixtureRepo; 'Microsoft Visual Studio Solution File'|Set-Content (Join-Path $d 'BusinessOS.sln'); $r=Invoke-ExpectFailure pwsh @('-NoProfile','-File',(Join-Path $d 'eng/doctor.ps1'),'-Mode','CrossPlatform','-SkipEnvironmentTests') $d 'BusinessOS.sln'; if($r.Combined -notmatch '0 project entries'){throw 'missing project count'} }
Assert 'doctor rejects missing UnitTests with concrete output' { $d=Copy-FixtureRepo; Remove-Item (Join-Path $d 'tests/BusinessOS.UnitTests/BusinessOS.UnitTests.csproj'); $r=Invoke-ExpectFailure pwsh @('-NoProfile','-File',(Join-Path $d 'eng/doctor.ps1'),'-Mode','CrossPlatform','-SkipEnvironmentTests') $d 'tests/BusinessOS.UnitTests/BusinessOS.UnitTests.csproj'; if($r.Combined -notmatch 'FAIL'){throw 'missing FAIL'} }
Assert 'doctor rejects global mismatch with concrete output' { $d=Copy-FixtureRepo; '{"sdk":{"version":"0.0.1"}}'|Set-Content (Join-Path $d 'global.json'); $r=Invoke-ExpectFailure pwsh @('-NoProfile','-File',(Join-Path $d 'eng/doctor.ps1'),'-Mode','CrossPlatform','-SkipEnvironmentTests') $d 'global.json SDK'; if($r.Combined -notmatch '0.0.1' -or $r.Combined -notmatch 'FAIL'){throw 'missing mismatch details'} }
Assert 'Assert-FileHash rejects placeholders and accepts valid checksum' { $f=New-FileWithHash 'abc'; $sha=(Get-FileHash $f -Algorithm SHA256).Hash; Assert-FileHash $f $sha SHA256|Out-Null; foreach($bad in '', 'abc', ('0'*64), ('1'*64), ('2'*64), ('3'*64), ('A'*64)){ $failed=$false; try{Assert-FileHash $f $bad SHA256|Out-Null}catch{$failed=$true}; if(-not $failed){throw "accepted bad checksum $bad"} } }
Assert 'Invoke-DownloadWithFallback uses second adapter after first failure' { $f=Join-Path ([IO.Path]::GetTempPath()) ([Guid]::NewGuid()); $source=New-FileWithHash 'ok'; $sha=(Get-FileHash $source -Algorithm SHA256).Hash; $adapter={param($url,$out) if($url -eq 'bad'){[pscustomobject]@{StatusCode=500;Bytes=0}}else{Copy-Item $source $out;[pscustomobject]@{StatusCode=200;Bytes=(Get-Item $out).Length}}}; $r=Invoke-DownloadWithFallback @('bad','good') $f $sha SHA256 $adapter; if($r.Url -ne 'good'){throw 'fallback did not reach good source'} }
Assert 'Invoke-DownloadWithFallback rejects empty and all-failed downloads' { $f=Join-Path ([IO.Path]::GetTempPath()) ([Guid]::NewGuid()); $sha='A'*64; $adapter={param($url,$out)''|Set-Content -NoNewline $out;[pscustomobject]@{StatusCode=200;Bytes=0}}; $failed=$false; try{Invoke-DownloadWithFallback @('empty') $f $sha SHA256 $adapter|Out-Null}catch{$failed=$true}; if(-not $failed){throw 'accepted empty download'} }
Assert 'Expand-VerifiedArchive accepts valid ZIP with tool.exe' { $zip=Join-Path ([IO.Path]::GetTempPath()) ([Guid]::NewGuid().ToString()+'.zip'); New-ZipArchive $zip 'tool.exe'; $dest=Join-Path ([IO.Path]::GetTempPath()) ([Guid]::NewGuid()); $exe=Expand-VerifiedArchive $zip $dest zip 'tool.exe'; if(-not(Test-Path $exe)){throw 'tool.exe missing after valid ZIP extraction'} }
Assert 'Expand-VerifiedArchive rejects valid ZIP without tool.exe' { $zip=Join-Path ([IO.Path]::GetTempPath()) ([Guid]::NewGuid().ToString()+'.zip'); New-ZipArchive $zip 'readme.txt'; $failed=$false; try{Expand-VerifiedArchive $zip (Join-Path ([IO.Path]::GetTempPath()) ([Guid]::NewGuid())) zip 'tool.exe'|Out-Null}catch{if($_.Exception.Message -match 'Expected executable missing'){$failed=$true}}; if(-not $failed){throw 'valid ZIP without tool.exe was not rejected'} }
Assert 'Expand-VerifiedArchive rejects corrupt and empty ZIP' { $bad=New-FileWithHash 'not zip'; $empty=Join-Path ([IO.Path]::GetTempPath()) ([Guid]::NewGuid().ToString()+'.zip'); New-Item -ItemType File -Path $empty|Out-Null; foreach($case in @(@($bad,'Invalid ZIP archive'),@($empty,'Archive is empty'))){$failed=$false; try{Expand-VerifiedArchive $case[0] (Join-Path ([IO.Path]::GetTempPath()) ([Guid]::NewGuid())) zip 'tool.exe'|Out-Null}catch{if($_.Exception.Message -match [regex]::Escape($case[1])){$failed=$true}}; if(-not $failed){throw "ZIP case was not rejected: $($case[1])"}} }
Assert 'Expand-VerifiedArchive accepts valid TAR.GZ with tool' { if(-not(Get-Command tar -ErrorAction SilentlyContinue)){Write-Host 'SKIPPED tar unavailable'; return}; $tgz=Join-Path ([IO.Path]::GetTempPath()) ([Guid]::NewGuid().ToString()+'.tar.gz'); New-TarGzArchive $tgz 'tool'; $dest=Join-Path ([IO.Path]::GetTempPath()) ([Guid]::NewGuid()); $exe=Expand-VerifiedArchive $tgz $dest 'tar.gz' 'tool'; if(-not(Test-Path $exe)){throw 'tool missing after valid TAR.GZ extraction'} }
Assert 'Expand-VerifiedArchive rejects valid TAR.GZ without tool' { if(-not(Get-Command tar -ErrorAction SilentlyContinue)){Write-Host 'SKIPPED tar unavailable'; return}; $tgz=Join-Path ([IO.Path]::GetTempPath()) ([Guid]::NewGuid().ToString()+'.tar.gz'); New-TarGzArchive $tgz 'readme.txt'; $failed=$false; try{Expand-VerifiedArchive $tgz (Join-Path ([IO.Path]::GetTempPath()) ([Guid]::NewGuid())) 'tar.gz' 'tool'|Out-Null}catch{if($_.Exception.Message -match 'Expected executable missing'){$failed=$true}}; if(-not $failed){throw 'valid TAR.GZ without tool was not rejected'} }
Assert 'Expand-VerifiedArchive rejects corrupt and empty TAR.GZ' { if(-not(Get-Command tar -ErrorAction SilentlyContinue)){Write-Host 'SKIPPED tar unavailable'; return}; $bad=New-FileWithHash 'not tar'; $empty=Join-Path ([IO.Path]::GetTempPath()) ([Guid]::NewGuid().ToString()+'.tar.gz'); New-Item -ItemType File -Path $empty|Out-Null; foreach($case in @(@($bad,'Invalid TAR.GZ archive'),@($empty,'Archive is empty'))){$failed=$false; try{Expand-VerifiedArchive $case[0] (Join-Path ([IO.Path]::GetTempPath()) ([Guid]::NewGuid())) 'tar.gz' 'tool'|Out-Null}catch{if($_.Exception.Message -match [regex]::Escape($case[1])){$failed=$true}}; if(-not $failed){throw "TAR.GZ case was not rejected: $($case[1])"}} }
Assert 'Invoke-CheckedCommand handles script path and argument with spaces' { $d=Join-Path ([IO.Path]::GetTempPath()) ('space dir '+[Guid]::NewGuid()); New-Item -ItemType Directory -Force $d|Out-Null; $script=Join-Path $d 'script with space.ps1'; 'param([string]$Value) Write-Output "VALUE=$Value"'|Set-Content $script; $r=Invoke-CheckedCommand $script @('hello world') $d; if(($r.StdOut -join '') -notmatch 'hello world'){throw 'argument with space was not preserved'} }
Assert 'Invoke-ProcessForTest handles large stdout and stderr concurrently' { $r=Invoke-ExpectSuccess pwsh @('-NoProfile','-Command','1..2000|%{Write-Output "out $_"; Write-Error "err $_" -ErrorAction Continue}') $Root; if($r.Output.Length -lt 1000 -or $r.Error.Length -lt 1000){throw 'missing stream output'} }
Assert 'cross-platform filter contains required projects and excludes Desktop/Infrastructure' { $p=Get-BusinessOSCrossPlatformFilterProjects $Root; foreach($r in 'BusinessOS.BuildingBlocks.Domain.csproj','BusinessOS.BuildingBlocks.Application.csproj','BusinessOS.UnitTests.csproj','BusinessOS.ArchitectureTests.csproj'){if(-not(($p|Split-Path -Leaf)-contains $r)){throw "missing $r"}}; if(($p -join ';') -match 'Desktop|Infrastructure'){throw 'excluded project present'} }
Assert 'Windows verifier fails outside Windows' { if(-not $IsWindows){ Invoke-ExpectFailure pwsh @('-NoProfile','-File',(Join-Path $Root 'eng/verify-windows.ps1')) $Root 'must run on Windows' | Out-Null } }
if($script:Failures -gt 0){exit 1}
